import React, { useState } from "react";
import "./EMR.css";

export default function EMR() {
  const [tab, setTab] = useState("notes");

  const [patient, setPatient] = useState({
    name: "",
    age: "",
    gender: "",
    mrn: "",
    visitId: "",
    department: "",
    photo: null
  });

  const [vitals, setVitals] = useState({
    hr: "",
    sys: "",
    dia: "",
    rr: "",
    spo2: "",
    temp: ""
  });

  const [redFlags, setRedFlags] = useState({
    chestPain: false,
    hypoxia: false,
    trauma: false,
    seizure: false
  });

  const [triage, setTriage] = useState("");
  const [nurse, setNurse] = useState("");

  // ================= FIXED AI LOGIC =================
  const aiLevel = () => {
    const { hr, sys, dia, rr, spo2, temp } = vitals;

    // no vitals entered
    if (!hr && !sys && !dia && !rr && !spo2 && !temp) {
      return "";
    }

    // LEVEL 1 – CRITICAL
    if (
      Number(spo2) < 90 ||
      Number(hr) > 130 ||
      Number(sys) < 90 ||
      redFlags.seizure ||
      redFlags.trauma
    ) {
      return "LEVEL 1";
    }

    // LEVEL 2 – EMERGENT
    if (
      redFlags.chestPain ||
      redFlags.hypoxia ||
      Number(temp) >= 39 ||
      Number(rr) > 25
    ) {
      return "LEVEL 2";
    }

    // LEVEL 3 – URGENT
    if (
      Number(hr) > 100 ||
      Number(rr) > 20 ||
      Number(temp) > 38
    ) {
      return "LEVEL 3";
    }

    // LEVEL 4 – SEMI URGENT
    if (hr || sys || spo2) {
      return "LEVEL 4";
    }

    // LEVEL 5 – NON URGENT
    return "LEVEL 5";
  };

  return (
    <div className="emr-wrapper">

      {/* ================= HEADER ================= */}
      <div className="emr-header">
        <div className="profile">
          <label>
            <input
              type="file"
              hidden
              accept="image/*"
              onChange={(e) =>
                setPatient({
                  ...patient,
                  photo: URL.createObjectURL(e.target.files[0])
                })
              }
            />
            <img
              src={patient.photo || "https://via.placeholder.com/80"}
              alt="patient"
            />
          </label>

          <div>
            <input placeholder="Patient Name" />
            <div className="sub">
              <input placeholder="Age" />
              <input placeholder="Gender" />
            </div>
          </div>
        </div>
      </div>

      {/* ================= VISIT INFO ================= */}
      <div className="visit-strip">
        <input placeholder="MRN" />
        <input placeholder="Visit ID" />
        <input placeholder="Department" />
      </div>

      {/* ================= TABS ================= */}
      <div className="tabs">
        <button
          className={tab === "notes" ? "active" : ""}
          onClick={() => setTab("notes")}
        >
          Clinical Notes
        </button>

        <button
          className={tab === "vitals" ? "active" : ""}
          onClick={() => setTab("vitals")}
        >
          Vitals
        </button>
      </div>

      {/* ================= CLINICAL NOTES ================= */}
      {tab === "notes" && (
        <div className="card">
          <label>Chief Complaint</label>
          <input />

          <label>History of Present Illness</label>
          <textarea />

          <label>Assessment</label>
          <textarea />

          <label>Plan</label>
          <textarea />
        </div>
      )}

      {/* ================= VITALS ================= */}
      {tab === "vitals" && (
        <div className="card">

          <h3>Vital Signs</h3>

          <div className="grid">
            <input placeholder="Heart Rate Normal: 60–100 bpm"
              onChange={e => setVitals({ ...vitals, hr: e.target.value })} />

            <input placeholder="BP Systolic Normal: 90–120 mmHg"
              onChange={e => setVitals({ ...vitals, sys: e.target.value })} />

            <input placeholder="BP Diastolic Normal: 60–80 mmHg"
              onChange={e => setVitals({ ...vitals, dia: e.target.value })} />

            <input placeholder="Respiratory Rate Normal: 12–20 /min"
              onChange={e => setVitals({ ...vitals, rr: e.target.value })} />

            <input placeholder="SpO₂ % Normal: 95–100 %"
              onChange={e => setVitals({ ...vitals, spo2: e.target.value })} />

            <input placeholder="Temperature °C Normal: 36.5–37.5 °C"
              onChange={e => setVitals({ ...vitals, temp: e.target.value })} />
          </div>

          {/* ===== RED FLAGS ===== */}
          <h3>Red Flags Detected</h3>
          <div className="checks">
            {Object.keys(redFlags).map((key) => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={redFlags[key]}
                  onChange={() =>
                    setRedFlags({ ...redFlags, [key]: !redFlags[key] })
                  }
                />
                {key}
              </label>
            ))}
          </div>

          {/* ===== AI LEVEL ===== */}
          {aiLevel() && (
            <div className="ai-box">
              <h3>AI Suggested Level</h3>
              <strong>{aiLevel()}</strong>
            </div>
          )}

          {/* ===== TRIAGE ===== */}
          <h3>Triage Level</h3>
          <div className="triage">
            {[
              { id: "LEVEL 1", label: "Level 1 Critical" },
              { id: "LEVEL 2", label: "Level 2 Emergent" },
              { id: "LEVEL 3", label: "Level 3 Urgent" },
              { id: "LEVEL 4", label: "Level 4 Semi-Urgent" },
              { id: "LEVEL 5", label: "Level 5 Non-Urgent" }
            ].map(l => (
              <button
                key={l.id}
                className={aiLevel() === l.id ? "active" : ""}
                onClick={() => setTriage(l.id)}
              >
                {l.label}
              </button>
            ))}
          </div>

          {/* ===== ISOLATION ===== */}
          <h3>Isolation</h3>
          <div className="checks">
            <label><input type="checkbox" /> Droplet</label>
            <label><input type="checkbox" /> Contact</label>
            <label><input type="checkbox" /> None</label>
          </div>

          {/* ===== NURSE ===== */}
          <label>Nurse Name</label>
          <input
            value={nurse}
            onChange={(e) => setNurse(e.target.value)}
          />
        </div>
      )}

      {/* ================= FOOTER ================= */}
      <div className="footer-btns">
        <button className="draft">Save Draft</button>
        <button className="complete">Complete Visit</button>
      </div>

    </div>
  );
}
